(()=>{const e=document.querySelector('[data-testid="notes-textarea"]'),t=document.querySelector('[data-testid="save-notes-btn"]');function s(){const e=document.querySelector('[data-testid="sessions-list"]');chrome.storage.local.get("sessions",t=>{const s=t.sessions||{};e.innerHTML="";for(const t in s){const o=document.createElement("div");o.style.marginBottom="8px";const n=document.createElement("span");n.textContent=t;const c=document.createElement("button");c.textContent="Restore",c.setAttribute("data-testid",`restore-session-${t}`),c.onclick=()=>{const e=s[t];chrome.windows.create({url:e})},o.appendChild(n),o.appendChild(c),e.appendChild(o)}})}document.addEventListener("DOMContentLoaded",()=>{chrome.storage.local.get("notes",t=>{e.value=t.notes||""}),s()}),t.addEventListener("click",()=>{chrome.storage.local.set({notes:e.value})}),document.querySelector('[data-testid="save-session-btn"]').addEventListener("click",async()=>{const e=prompt("Enter Session Name");if(!e)return;const t=(await chrome.tabs.query({currentWindow:!0})).map(e=>e.url);chrome.storage.local.get("sessions",o=>{const n=o.sessions||{};n[e]=t,chrome.storage.local.set({sessions:n},()=>{alert("Session Saved "),s()})})})})();